public XYDataItem addOrUpdate(Number x, Number y) {
    if (x == null) {
        throw new IllegalArgumentException("Null 'x' argument.");
    }

    XYDataItem overwritten = null;
    int index = indexOf(x);
    if (index >= 0 && !this.allowDuplicateXValues) {
        XYDataItem existing = (XYDataItem) this.data.get(index);
        try {
            overwritten = (XYDataItem) existing.clone();
        } catch (CloneNotSupportedException e) {
            throw new SeriesException("Couldn't clone XYDataItem!");
        }
        existing.setY(y);
    } else {
        int insertIndex = (this.autoSort && index < 0) ? -index - 1 : this.data.size();
        this.data.add(insertIndex, new XYDataItem(x, y));

        if (getItemCount() > this.maximumItemCount) {
            this.data.remove(0);
        }
    }
    fireSeriesChanged();
    return overwritten;
}

public XYDataItem addOrUpdate(Number x, Number y) {
    if (x == null) {
        throw new IllegalArgumentException("Null 'x' argument.");
    }

    XYDataItem overwritten = null;
    int index = indexOf(x);
    if (index >= 0 && !this.allowDuplicateXValues) {
        XYDataItem existing = (XYDataItem) this.data.get(index);
        try {
            overwritten = (XYDataItem) existing.clone();
        }
        catch (CloneNotSupportedException e) {
            throw new SeriesException("Couldn't clone XYDataItem!");
        }
        existing.setY(y);
    } else {
        int insertionPoint = index;
        if (index < 0) {
            insertionPoint = -index - 1;
        } else if (this.allowDuplicateXValues) {
            insertionPoint = index + 1;
        }

        XYDataItem newItem = new XYDataItem(x, y);
        this.data.add(insertionPoint, newItem);

        if (this.autoSort) {
            Collections.sort(this.data);
        }

        if (getItemCount() > this.maximumItemCount) {
            this.data.remove(0);
        }
    }

    fireSeriesChanged();
    return overwritten;
}
